"use strict";

const fs = require("fs");
const path = require("path");
const { execFileSync } = require("child_process");

const androidBuildDir = path.resolve(__dirname, "..");
const repositoryRoot = path.resolve(androidBuildDir, "..");
const outputFile = path.join(androidBuildDir, "www", "build-info.js");

// Files that represent meaningful application changes. Generated files,
// dependencies, SDKs and Gradle output are intentionally excluded.
const sourceFiles = [
    "index.html",
    "style.css",
    "script.js",
    "android_build/www/index.html",
    "android_build/www/style.css",
    "android_build/www/script.js",
    "android_build/www/pwa.js",
    "android_build/www/sw.js",
    "android_build/build.bat",
    "android_build/scripts/generate-build-date.js",
    "android_build/scripts/patch-media-session-plugin.js",
    "android_build/scripts/configure-android-background-playback.js",
    "android_build/package.json",
    "android_build/package-lock.json"
];

function runGit(args) {
    return execFileSync("git", args, {
        cwd: repositoryRoot,
        encoding: "utf8",
        stdio: ["ignore", "pipe", "ignore"]
    }).trim();
}

function formatLocalDate(date) {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, "0");
    const day = String(date.getDate()).padStart(2, "0");
    return `${year}-${month}-${day}`;
}

function getNewestFileDate(relativeFiles) {
    const dates = relativeFiles
        .map(relativePath => path.join(repositoryRoot, relativePath))
        .filter(filePath => fs.existsSync(filePath))
        .map(filePath => fs.statSync(filePath).mtime)
        .filter(date => !Number.isNaN(date.getTime()));

    if (dates.length === 0) {
        throw new Error("No source files were found for Android build-date generation.");
    }

    return new Date(Math.max(...dates.map(date => date.getTime())));
}

function resolveLastUpdatedDate() {
    try {
        if (runGit(["rev-parse", "--is-inside-work-tree"]) === "true") {
            const dirtyFiles = runGit(["status", "--porcelain", "--", ...sourceFiles]);

            // Uncommitted source edits should be reflected immediately.
            if (dirtyFiles) {
                return {
                    date: getNewestFileDate(sourceFiles),
                    source: "working-tree"
                };
            }

            const committedDate = runGit([
                "log",
                "-1",
                "--format=%cs",
                "--",
                ...sourceFiles
            ]);

            if (/^\d{4}-\d{2}-\d{2}$/.test(committedDate)) {
                return {
                    dateOnly: committedDate,
                    source: "git-commit"
                };
            }
        }
    } catch (error) {
        // Git may be unavailable in extracted source archives. File timestamps
        // are a deterministic fallback and do not change merely because APK is run.
    }

    return {
        date: getNewestFileDate(sourceFiles),
        source: "source-file"
    };
}

const resolved = resolveLastUpdatedDate();
const lastUpdated = resolved.dateOnly || formatLocalDate(resolved.date);
const output = `// Generated by scripts/generate-build-date.js. Do not edit manually.\n` +
    `window.YTMP_BUILD_INFO = Object.freeze({ lastUpdated: ${JSON.stringify(lastUpdated)} });\n`;

fs.mkdirSync(path.dirname(outputFile), { recursive: true });

const existing = fs.existsSync(outputFile)
    ? fs.readFileSync(outputFile, "utf8")
    : "";

if (existing !== output) {
    fs.writeFileSync(outputFile, output, "utf8");
}

console.log(`Android Last Updated date: ${lastUpdated} (${resolved.source})`);
